package framework.entity.src.org.ofbiz.entity;

public abstract class DelegatorFactory implements Factory < Delegator , String > { public static final String module = DelegatorFactoryImpl . class . getName ( ) ; private static final ConcurrentHashMap < String , Delegator > delegatorCache = new ConcurrentHashMap < String , Delegator > ( ) ; public static Delegator getDelegator ( String delegatorName ) { if ( delegatorName == null ) { delegatorName = "default" ; } do { Delegator delegator = delegatorCache . get ( delegatorName ) ; if ( delegator != null ) { delegator . initEntityEcaHandler ( ) ; delegator . initDistributedCacheClear ( ) ; return delegator ; } try { delegator = UtilObject . getObjectFromFactory ( DelegatorFactory . class , delegatorName ) ; } catch ( ClassNotFoundException e ) { Debug . logError ( e , module ) ; } delegatorCache . putIfAbsent ( delegatorName , delegator ) ; } while ( true ) ; } }